import styled, { keyframes } from "styled-components";
import { getColors } from "../../Styles/colors";
import { GrooveProps } from "./types";

const slideRight = keyframes`
  from {
    left: 0;
  }
  to {
    left: 17rem;
  }
`;

export const Container = styled.div`
  width: 100%;
  height: 35rem;
  background-color: ${(props) => getColors(props.theme).background};
  position: relative;
  overflow: hidden;
`;

export const BackgroundImage = styled.img`
  width: 100%;
  height: auto;
  position: absolute;
  top: 0;
  right: 0;
  display: block;
  object-fit: cover;
`;

export const VinylRecord = styled.div`
  height: 35rem;
  width: 35rem;
  border-radius: 300px;
  background-color: black;
  position: absolute;
  top: 0;
  display: flex;
  justify-content: center;
  align-items: center;

  animation: ${slideRight} 2s ease forwards;
`;

export const Sleeve = styled.img`
  height: 35rem;
  width: 35rem;
  border-radius: 2%;
  position: relative;
  z-index; 100;
`;

export const Circle = styled.div<GrooveProps>`
  width: ${({ diameter }) => diameter}rem;
  height: ${({ diameter }) => diameter}rem;
  border-radius: 50%;
  ${({ color }) => (color ? `background-color: ${color};` : ``)}
  position: absolute;
  border: 1px solid #444;
`;
